"""
台本テキスト → TSV変換スクリプト
入力フォーマット: [文字数][話者][本文] が連続した文字列
出力フォーマット: 話者\t本文\t\tSE\tキーワード（5列）
"""
import re
import sys
import os

NO_SE_SPEAKERS = {'ナレーション', 'タイトル'}
SE_INTERVAL = 10

SPEAKER_PATTERN = re.compile(
    r'(\d+)(ナレーション|タイトル|イッチ|スレ民[1-6])(.*?)(?=\d+(?:ナレーション|タイトル|イッチ|スレ民[1-6])|$)',
    re.DOTALL
)

def extract_keyword(speaker: str, text: str) -> str:
    if speaker in NO_SE_SPEAKERS:
        return ''
    m = re.search(r'[\u4e00-\u9fa5]{2,4}', text)
    if m:
        return m.group(0)
    m = re.search(r'[\u30a1-\u30f6]{2,6}', text)
    if m:
        return m.group(0)
    return ''

def convert(raw: str) -> str:
    matches = SPEAKER_PATTERN.findall(raw)
    rows = []
    utterance_count = 0
    se_index = 0

    for _, speaker, text in matches:
        text = text.strip().replace('\n', '').replace('\r', '')
        if not text:
            continue

        se = ''
        if speaker not in NO_SE_SPEAKERS:
            utterance_count += 1
            if utterance_count >= SE_INTERVAL:
                se = 'SE1' if se_index % 2 == 0 else 'SE2'
                se_index += 1
                utterance_count = 0

        keyword = extract_keyword(speaker, text)
        rows.append(f'{speaker}\t{text}\t\t{se}\t{keyword}')

    return '\n'.join(rows)


